mapper.select:
select p.id, p.project_code, p.name, p.description, p.status, p.life_cycle_model, p.owner_id, u.real_name as owner_name, p.start_date, p.end_date, p.progress_rate, p.planned_budget, p.actual_cost, (select count(1) from project_member pm where pm.project_id = p.id) as member_count from project_info p left join sys_user u on u.id = p.owner_id where p.is_deleted = 0
and (p.name like concat('%', #{query.keyword}, '%') or p.project_code like concat('%', #{query.keyword}, '%'))
and p.status = #{query.status}
and p.life_cycle_model = #{query.lifeCycleModel}
and p.owner_id = #{query.ownerId}
order by p.created_at desc

mapper.update:
update project_info
set status = #{status},
    actual_start_date = case
        when #{actualStartDate} is not null and actual_start_date is null then #{actualStartDate}
        else actual_start_date
    end,
    actual_end_date = case
        when #{actualEndDate} is not null then #{actualEndDate}
        when #{clearActualEndDate} then null
        else actual_end_date
    end,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where id = #{projectId}
  and is_deleted = 0

update project_info
set is_deleted = 1,
    updated_by = #{updatedBy},
    updated_at = #{updatedAt}
where id = #{projectId}
  and is_deleted = 0

mapper.insert:
